import type {
  DIDResolutionOptions,
  DIDResolutionResult,
  DIDResolver,
  ParsedDID,
} from "did-resolver";

import { DID_RESOLUTION_ERROR_CODES } from "./constants.ts";
import { resolve as resolveV1 } from "./resolvers/v1.ts";
import { validate } from "./validator.ts";

export interface ResolverOptions {
  /**
   * Only used with EBSI DID method v1.
   */
  registry?: string;
}

/**
 * EBSI DID Resolver for the "did:ebsi:" method. Supports only Legal Entities (DID Method v1).
 * @param resolverOptions - Resolver options
 * @returns The EBSI DID resolver
 */
export function getResolver(
  resolverOptions: ResolverOptions,
): Record<"ebsi", DIDResolver> {
  async function resolve(
    did: string,
    _: ParsedDID,
    __: unknown,
    didResolutionOptions?: DIDResolutionOptions,
  ): Promise<DIDResolutionResult> {
    if (typeof resolverOptions !== "object") {
      return {
        // eslint-disable-next-line unicorn/no-null
        didDocument: null,
        didDocumentMetadata: {},
        didResolutionMetadata: {
          error: DID_RESOLUTION_ERROR_CODES.CONFIGURATION_ERROR,
          message: "Invalid or missing resolver options",
        },
      };
    }

    // Validate DID
    try {
      validate(did);
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      return {
        // eslint-disable-next-line unicorn/no-null
        didDocument: null,
        didDocumentMetadata: {},
        didResolutionMetadata: {
          error: "invalidDid",
          message,
        },
      };
    }

    return resolveV1(did, resolverOptions.registry, didResolutionOptions);
  }

  return { ebsi: resolve };
}
